// ── Role configuration (v2: simplified, combat behavior lives in unified tree) ──

#[derive(Clone, Debug)]
pub struct RoleConfig {
    pub aggro_on_hit: bool,  // does this NPC fight back when attacked?
}

pub fn role_config(role: &str) -> RoleConfig {
    match role {
        "historian" => RoleConfig { aggro_on_hit: false },
        // All other roles fight back when hit (tree's reactive layer handles the rest)
        _ => RoleConfig { aggro_on_hit: true },
    }
}

// ── Default personality per role ──

pub fn default_personality_for_role(role: &str) -> NpcPersonality {
    match role {
        "hostile" => NpcPersonality {
            npc_id: 0, aggression: 0.8, sociability: 0.1, curiosity: 0.2,
            courage: 0.7, empathy: 0.1, discipline: 0.3,
        },
        "hostile_defensive" => NpcPersonality {
            npc_id: 0, aggression: 0.6, sociability: 0.1, curiosity: 0.2,
            courage: 0.5, empathy: 0.1, discipline: 0.5,
        },
        "trader" => NpcPersonality {
            npc_id: 0, aggression: 0.1, sociability: 0.8, curiosity: 0.5,
            courage: 0.3, empathy: 0.6, discipline: 0.6,
        },
        "traveller" => NpcPersonality {
            npc_id: 0, aggression: 0.2, sociability: 0.6, curiosity: 0.8,
            courage: 0.5, empathy: 0.5, discipline: 0.4,
        },
        "historian" => NpcPersonality {
            npc_id: 0, aggression: 0.0, sociability: 0.7, curiosity: 0.9,
            courage: 0.3, empathy: 0.7, discipline: 0.8,
        },
        "adventurer" => NpcPersonality {
            npc_id: 0, aggression: 0.5, sociability: 0.5, curiosity: 0.7,
            courage: 0.8, empathy: 0.4, discipline: 0.5,
        },
        "guard" => NpcPersonality {
            npc_id: 0, aggression: 0.4, sociability: 0.4, curiosity: 0.3,
            courage: 0.7, empathy: 0.5, discipline: 0.7,
        },
        "healer" => NpcPersonality {
            npc_id: 0, aggression: 0.0, sociability: 0.7, curiosity: 0.5,
            courage: 0.4, empathy: 0.9, discipline: 0.7,
        },
        // Unknown roles: moderate across the board
        _ => NpcPersonality {
            npc_id: 0, aggression: 0.5, sociability: 0.3, curiosity: 0.3,
            courage: 0.5, empathy: 0.3, discipline: 0.4,
        },
    }
}

// ── Emotion system ──

/// Get a named emotion value from an NpcEmotion row.
pub fn get_emotion_value(emotion: &NpcEmotion, name: &str) -> f32 {
    match name {
        "anger" => emotion.anger,
        "fear" => emotion.fear,
        "joy" => emotion.joy,
        "sadness" => emotion.sadness,
        "surprise" => emotion.surprise,
        "disgust" => emotion.disgust,
        _ => 0.0,
    }
}

/// Set a named emotion value on an NpcEmotion row.
fn set_emotion_value(emotion: &mut NpcEmotion, name: &str, value: f32) {
    match name {
        "anger" => emotion.anger = value,
        "fear" => emotion.fear = value,
        "joy" => emotion.joy = value,
        "sadness" => emotion.sadness = value,
        "surprise" => emotion.surprise = value,
        "disgust" => emotion.disgust = value,
        _ => {}
    }
}

/// Trigger an emotion change on an NPC. Clamps to 0.0-1.0. Creates row if missing.
pub fn trigger_emotion(ctx: &ReducerContext, npc_id: u64, emotion: &str, delta: f32) {
    let mut emo = ctx.db.npc_emotion().npc_id().find(&npc_id).unwrap_or(NpcEmotion {
        npc_id, anger: 0.0, fear: 0.0, joy: 0.0, sadness: 0.0, surprise: 0.0, disgust: 0.0,
    });
    let current = get_emotion_value(&emo, emotion);
    let new_val = (current + delta).clamp(0.0, 1.0);
    set_emotion_value(&mut emo, emotion, new_val);

    if ctx.db.npc_emotion().npc_id().find(&npc_id).is_some() {
        ctx.db.npc_emotion().npc_id().update(emo);
    } else {
        ctx.db.npc_emotion().insert(emo);
    }
}

/// Apply emotion decay toward personality baseline each tick.
/// decay_rate = 0.02 + discipline * 0.13
/// Baselines: anger=aggression, fear=1-courage, joy=sociability, sadness/surprise/disgust=0
pub fn apply_emotion_decay(ctx: &ReducerContext, npc_id: u64) {
    let emo = match ctx.db.npc_emotion().npc_id().find(&npc_id) {
        Some(e) => e,
        None => return, // no emotion row = nothing to decay
    };
    let personality = ctx.db.npc_personality().npc_id().find(&npc_id);
    let (anger_base, fear_base, joy_base, decay_rate) = match &personality {
        Some(p) => (
            p.aggression,
            (1.0 - p.courage).max(0.0),
            p.sociability,
            0.02 + p.discipline * 0.13,
        ),
        None => (0.0, 0.0, 0.0, 0.05), // fallback if no personality
    };

    let lerp = |current: f32, baseline: f32, rate: f32| -> f32 {
        current + (baseline - current) * rate
    };

    let updated = NpcEmotion {
        npc_id,
        anger: lerp(emo.anger, anger_base, decay_rate),
        fear: lerp(emo.fear, fear_base, decay_rate),
        joy: lerp(emo.joy, joy_base, decay_rate),
        sadness: lerp(emo.sadness, 0.0, decay_rate),
        surprise: lerp(emo.surprise, 0.0, decay_rate),
        disgust: lerp(emo.disgust, 0.0, decay_rate),
    };

    ctx.db.npc_emotion().npc_id().update(updated);
}

// ── Legacy NpcAction for submit_npc_actions reducer ──

#[derive(serde::Deserialize)]
#[serde(tag = "action", rename_all = "snake_case")]
pub enum NpcAction {
    MoveTo { x: f32, z: f32 },
    Attack { target_type: String, target_id: String },
    Say { message: String },
    Wander,
}

// ── Action/Condition enum for behavior trees ──

#[derive(Clone, Debug, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum NpcBtAction {
    // ── Conditions (return Success/Failure, no side effects) ──

    // World state
    EnemyInRange,
    EnemyDetected,
    HealthBelow(f32),
    NoTarget,
    IsNightTime,
    IsDayTime,
    GoldAbove(i32),
    GoldBelow(i32),
    HasItem(String),
    NpcNearby,
    NpcNearbyWithRole(String),
    PlayerNearby,
    AtPoi(String),
    GoalActive(String),
    ManaAbove(f32),
    StaminaAbove(f32),

    // v2: Emotion gates
    EmotionAbove(String, f32),
    EmotionBelow(String, f32),
    EmotionDominant(String),

    // v2: Identity/knowledge conditions
    HasKnowledge(String),                      // has any knowledge in this category
    StrengthAdvantage(f32),                    // NPC stronger than target by this ratio
    IsBeingAttacked,                           // recent "took_damage" event
    BeingAddressedInConversation,              // recent unhandled "heard_chat"

    // ── Combat actions ──
    Attack,
    Chase,
    Flee,
    Wander,

    // ── Shared actions ──
    Say(String),
    TravelTo { x: f32, z: f32 },
    Wait(f32),

    // ── Life/unified tree actions ──
    TravelToPoi(String),
    GoHome,
    PickUpNearby,
    Rest,
    SayToNpc { npc_id: u64, message: String },
    SetBelief { subject: String, predicate: String, object: String },
    RequestLlmDecision(String),

    // v2: Entity-targeting actions (knowledge-gated)
    TravelToEntity { entity_type: String, entity_id: u64 },
    AttackEntity { entity_type: String, entity_id: u64 },
    SayToEntity { entity_type: String, entity_id: u64, message: String },

    // v2: Exploration (vague, no knowledge required)
    SearchFor(String),

    // v2: Inline identity updates (no LLM cost)
    AddKnowledge { category: String, fact: String },
    AdjustRelationship { target: String, delta: i32 },
    TriggerEmotionAction { emotion: String, delta: f32 },

    // v2: Conversation protocol
    SayTemplate(String),
    SayFromKnowledge(String),
    SayFromBelief(String),

    // v2: Tree lifecycle
    RequestNewTree,
    KeepDistance(f32),
    Follow { distance: f32 },
}

// ── Speech templates ──

pub fn get_template_text(template_id: &str) -> String {
    match template_id {
        "guard_greeting" => "Halt! State your business.".to_string(),
        "trader_greeting" => "Welcome! Browse my wares.".to_string(),
        "healer_greeting" => "Are you in need of healing?".to_string(),
        "historian_greeting" => "Ah, a curious soul! What would you like to know?".to_string(),
        "hostile_dismissal" => "Get away from me.".to_string(),
        "nervous_deflection" => "I... I don't want to talk about that.".to_string(),
        "cheerful_ignorance" => "Ha! I wouldn't know, but isn't it a lovely day?".to_string(),
        "generic_acknowledgment" => "Hmm, I see.".to_string(),
        "busy_response" => "Not now, I'm busy.".to_string(),
        "farewell" => "Safe travels.".to_string(),
        "greeting_response" => "Hello, traveler!".to_string(),
        "confused" => "I'm not sure about that.".to_string(),
        _ => String::new(),
    }
}

// ── Context for tree evaluation ──

pub struct TreeEvalContext<'a> {
    pub is_night: bool,
    pub nearby_npcs: &'a [Npc],
    pub nearby_pois: &'a [(PointOfInterest, f32)], // (poi, distance)
}

impl<'a> Default for TreeEvalContext<'a> {
    fn default() -> Self {
        Self { is_night: false, nearby_npcs: &[], nearby_pois: &[] }
    }
}

// ── Stateless behavior tree evaluator ──

pub fn evaluate_tree(
    ctx: &ReducerContext,
    tree: &Behavior<NpcBtAction>,
    npc: &Npc,
    target: Option<&Player>,
    eval_ctx: &TreeEvalContext,
) -> Option<NpcBtAction> {
    match tree {
        Behavior::Action(action) => {
            let ok = || Some(action.clone());
            match action {
                // ── Conditions ──
                NpcBtAction::EnemyInRange => {
                    target.filter(|p| npc.position.distance_to(&p.position) <= ATTACK_RANGE)
                        .map(|_| action.clone())
                }
                NpcBtAction::EnemyDetected => target.map(|_| action.clone()),
                NpcBtAction::HealthBelow(threshold) => {
                    let pct = npc.health as f32 / npc.max_health as f32;
                    if pct < *threshold { ok() } else { None }
                }
                NpcBtAction::NoTarget => if target.is_none() { ok() } else { None },
                NpcBtAction::IsNightTime => if eval_ctx.is_night { ok() } else { None },
                NpcBtAction::IsDayTime => if !eval_ctx.is_night { ok() } else { None },
                NpcBtAction::GoldAbove(amount) => if npc.gold > *amount { ok() } else { None },
                NpcBtAction::GoldBelow(amount) => if npc.gold < *amount { ok() } else { None },
                NpcBtAction::HasItem(item_name) => {
                    let has = ctx.db.npc_inventory_item().iter()
                        .any(|inv| inv.npc_id == npc.id && {
                            ctx.db.item_def().id().find(&inv.item_def_id)
                                .map_or(false, |d| d.name == *item_name)
                        });
                    if has { ok() } else { None }
                }
                NpcBtAction::NpcNearby => if !eval_ctx.nearby_npcs.is_empty() { ok() } else { None },
                NpcBtAction::NpcNearbyWithRole(role) => {
                    if eval_ctx.nearby_npcs.iter().any(|n| n.role == *role) { ok() } else { None }
                }
                NpcBtAction::PlayerNearby => if target.is_some() { ok() } else { None },
                NpcBtAction::AtPoi(poi_name) => {
                    if eval_ctx.nearby_pois.iter().any(|(p, d)| p.name == *poi_name && *d <= p.radius) {
                        ok()
                    } else { None }
                }
                NpcBtAction::GoalActive(desc) => {
                    let active = ctx.db.npc_goal().iter()
                        .any(|g| g.npc_id == npc.id && g.status == GoalStatus::Active
                            && g.description.contains(desc.as_str()));
                    if active { ok() } else { None }
                }
                NpcBtAction::ManaAbove(pct) => {
                    if npc.max_mana > 0 && (npc.mana as f32 / npc.max_mana as f32) > *pct { ok() } else { None }
                }
                NpcBtAction::StaminaAbove(pct) => {
                    if npc.max_stamina > 0 && (npc.stamina as f32 / npc.max_stamina as f32) > *pct { ok() } else { None }
                }

                // ── v2 Emotion conditions ──
                NpcBtAction::EmotionAbove(emotion, threshold) => {
                    let emo = ctx.db.npc_emotion().npc_id().find(&npc.id);
                    let val = emo.map_or(0.0, |e| get_emotion_value(&e, emotion));
                    if val > *threshold { ok() } else { None }
                }
                NpcBtAction::EmotionBelow(emotion, threshold) => {
                    let emo = ctx.db.npc_emotion().npc_id().find(&npc.id);
                    let val = emo.map_or(0.0, |e| get_emotion_value(&e, emotion));
                    if val < *threshold { ok() } else { None }
                }
                NpcBtAction::EmotionDominant(emotion) => {
                    if let Some(emo) = ctx.db.npc_emotion().npc_id().find(&npc.id) {
                        let vals = [
                            ("anger", emo.anger), ("fear", emo.fear), ("joy", emo.joy),
                            ("sadness", emo.sadness), ("surprise", emo.surprise), ("disgust", emo.disgust),
                        ];
                        let max = vals.iter().max_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
                        if max.map_or(false, |(name, _)| *name == emotion.as_str()) { ok() } else { None }
                    } else { None }
                }

                // ── v2 Identity/knowledge conditions ──
                NpcBtAction::HasKnowledge(category) => {
                    let has = ctx.db.npc_knowledge().iter()
                        .any(|k| k.npc_id == npc.id && k.category == *category);
                    if has { ok() } else { None }
                }
                NpcBtAction::StrengthAdvantage(threshold) => {
                    if let Some(player) = target {
                        let npc_power = npc.level as f32 * (npc.health as f32 / npc.max_health as f32);
                        let player_power = player.level as f32 * (player.health as f32 / player.max_health as f32);
                        let advantage = if player_power > 0.0 { (npc_power - player_power) / player_power } else { 1.0 };
                        if advantage >= *threshold { ok() } else { None }
                    } else { None }
                }
                NpcBtAction::IsBeingAttacked => {
                    if has_recent_event(ctx, npc.id, "took_damage", 5000) { ok() } else { None }
                }
                NpcBtAction::BeingAddressedInConversation => {
                    if has_unhandled_chat(ctx, npc.id) { ok() } else { None }
                }

                // ── Actions — always succeed, return themselves for execution ──
                _ => ok(),
            }
        }
        Behavior::Select(children) => {
            children.iter().find_map(|child| evaluate_tree(ctx, child, npc, target, eval_ctx))
        }
        Behavior::Sequence(children) => {
            let mut last = None;
            for child in children {
                match evaluate_tree(ctx, child, npc, target, eval_ctx) {
                    Some(action) => last = Some(action),
                    None => return None,
                }
            }
            last
        }
        Behavior::If(cond, if_true, if_false) => {
            if evaluate_tree(ctx, cond, npc, target, eval_ctx).is_some() {
                evaluate_tree(ctx, if_true, npc, target, eval_ctx)
            } else {
                evaluate_tree(ctx, if_false, npc, target, eval_ctx)
            }
        }
        Behavior::Invert(child) => {
            match evaluate_tree(ctx, child, npc, target, eval_ctx) {
                Some(_) => None,
                None => Some(NpcBtAction::Wander),
            }
        }
        Behavior::AlwaysSucceed(child) => {
            evaluate_tree(ctx, child, npc, target, eval_ctx);
            Some(NpcBtAction::Wander)
        }
        _ => None,
    }
}

// ── Execute a single BT action (combat or plan) ──

pub fn execute_bt_action(
    ctx: &ReducerContext,
    npc: &Npc,
    action: &NpcBtAction,
    target: Option<&Player>,
) {
    match action {
        NpcBtAction::Attack => {
            if let Some(player) = target {
                if npc.position.distance_to(&player.position) <= ATTACK_RANGE {
                    let dmg = crate::skill::npc_damage(npc.level);
                    let new_health = player.health - dmg;
                    log::info!("[NPC {}] attack player (dmg={}, hp: {} → {})", npc.id, dmg, player.health, new_health);
                    if new_health <= 0 {
                        respawn_player(ctx, player);
                        // Emotion: NPC won the fight
                        trigger_emotion(ctx, npc.id, "joy", 0.3);
                        trigger_emotion(ctx, npc.id, "fear", -0.2);
                    } else {
                        ctx.db.player().identity().update(Player {
                            health: new_health,
                            ..(*player).clone()
                        });
                    }
                }
            }
        }
        NpcBtAction::Chase => {
            if let Some(player) = target {
                let (dx, dz) = direction_to(&npc.position, &player.position);
                let new_x = (npc.position.x + dx * NPC_CHASE_STEP).clamp(WORLD_MIN, WORLD_MAX);
                let new_z = (npc.position.z + dz * NPC_CHASE_STEP).clamp(WORLD_MIN, WORLD_MAX);
                log::debug!("[NPC {}] chase toward player", npc.id);
                ctx.db.npc().id().update(Npc {
                    position: Position { x: new_x, y: NPC_GROUND_Y, z: new_z },
                    ..(*npc).clone()
                });
            }
        }
        NpcBtAction::Flee => {
            if let Some(player) = target {
                let (dx, dz) = direction_to(&npc.position, &player.position);
                let new_x = (npc.position.x - dx * NPC_CHASE_STEP).clamp(WORLD_MIN, WORLD_MAX);
                let new_z = (npc.position.z - dz * NPC_CHASE_STEP).clamp(WORLD_MIN, WORLD_MAX);
                log::debug!("[NPC {}] flee from player", npc.id);
                ctx.db.npc().id().update(Npc {
                    position: Position { x: new_x, y: NPC_GROUND_Y, z: new_z },
                    ..(*npc).clone()
                });
            }
        }
        NpcBtAction::Wander => {
            use spacetimedb::rand::Rng;
            let dx = (ctx.rng().gen::<f32>() * 2.0 - 1.0) * NPC_MOVE_RANGE;
            let dz = (ctx.rng().gen::<f32>() * 2.0 - 1.0) * NPC_MOVE_RANGE;
            let new_x = (npc.position.x + dx).clamp(WORLD_MIN, WORLD_MAX);
            let new_z = (npc.position.z + dz).clamp(WORLD_MIN, WORLD_MAX);
            ctx.db.npc().id().update(Npc {
                position: Position { x: new_x, y: NPC_GROUND_Y, z: new_z },
                ..(*npc).clone()
            });
        }
        NpcBtAction::Say(text) => {
            let text = text.chars().take(NPC_CHAT_MAX_LENGTH).collect::<String>();
            if !text.is_empty() {
                log::info!("[NPC {}] say: \"{}\"", npc.id, text);
                ctx.db.npc_chat_message().insert(crate::NpcChatMessage {
                    scheduled_id: 0,
                    scheduled_at: ScheduleAt::Time(ctx.timestamp + Duration::from_millis(NPC_CHAT_MESSAGE_EXPIRE_MS)),
                    npc_id: npc.id,
                    text,
                    position: npc.position.clone(),
                });
            }
        }
        NpcBtAction::TravelTo { x, z } => {
            let clamped_x = x.clamp(WORLD_MIN, WORLD_MAX);
            let clamped_z = z.clamp(WORLD_MIN, WORLD_MAX);
            log::info!("[NPC {}] travel_to ({:.1}, {:.1})", npc.id, clamped_x, clamped_z);
            if ctx.db.npc_destination().npc_id().find(&npc.id).is_some() {
                ctx.db.npc_destination().npc_id().update(NpcDestination {
                    npc_id: npc.id, target_x: clamped_x, target_z: clamped_z,
                });
            } else {
                ctx.db.npc_destination().insert(NpcDestination {
                    npc_id: npc.id, target_x: clamped_x, target_z: clamped_z,
                });
            }
        }
        NpcBtAction::Wait(_seconds) => {
            // Wait is a no-op each tick; plan step advancement handles the timer
        }
        NpcBtAction::TravelToPoi(poi_name) => {
            // Look up POI coordinates by name
            for poi in ctx.db.point_of_interest().iter() {
                if poi.name == *poi_name {
                    execute_bt_action(ctx, npc, &NpcBtAction::TravelTo { x: poi.x, z: poi.z }, None);
                    return;
                }
            }
            log::warn!("[NPC {}] POI '{}' not found", npc.id, poi_name);
        }
        NpcBtAction::GoHome => {
            execute_bt_action(ctx, npc, &NpcBtAction::TravelTo { x: npc.home_x, z: npc.home_z }, None);
        }
        NpcBtAction::PickUpNearby => {
            // Find nearest ground item and pick it up into NPC inventory
            let mut nearest: Option<(crate::GroundItem, f32)> = None;
            for item in ctx.db.ground_item().iter() {
                let d = npc.position.distance_to(&item.position);
                if d <= PICKUP_RANGE {
                    if nearest.as_ref().map_or(true, |(_, nd)| d < *nd) {
                        nearest = Some((item, d));
                    }
                }
            }
            if let Some((item, _)) = nearest {
                // Find empty slot
                let occupied: Vec<i32> = ctx.db.npc_inventory_item().iter()
                    .filter(|inv| inv.npc_id == npc.id)
                    .map(|inv| inv.slot)
                    .collect();
                for slot in 0..NPC_INVENTORY_SLOTS {
                    if !occupied.contains(&slot) {
                        ctx.db.npc_inventory_item().insert(NpcInventoryItem {
                            id: 0, npc_id: npc.id, slot,
                            item_def_id: item.item_def_id, quantity: item.quantity,
                        });
                        ctx.db.ground_item().scheduled_id().delete(&item.scheduled_id);
                        log::info!("[NPC {}] picked up item def {}", npc.id, item.item_def_id);
                        break;
                    }
                }
            }
        }
        NpcBtAction::Rest => {
            // Stand still, boosted regen handled in tick_npcs
        }
        NpcBtAction::SayToNpc { npc_id: target_npc_id, message } => {
            let text = message.chars().take(NPC_CHAT_MAX_LENGTH).collect::<String>();
            if !text.is_empty() {
                log::info!("[NPC {}] say to NPC {}: \"{}\"", npc.id, target_npc_id, text);
                ctx.db.npc_chat_message().insert(crate::NpcChatMessage {
                    scheduled_id: 0,
                    scheduled_at: ScheduleAt::Time(ctx.timestamp + Duration::from_millis(NPC_CHAT_MESSAGE_EXPIRE_MS)),
                    npc_id: npc.id,
                    text: text.clone(),
                    position: npc.position.clone(),
                });
                // Log event on target NPC
                log_npc_event(ctx, *target_npc_id, "heard_npc_chat",
                    &format!(r#"{{"from_npc":{},"text":"{}"}}"#, npc.id, text.replace('"', "\\\"")));
            }
        }
        NpcBtAction::SetBelief { subject, predicate, object } => {
            let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
            let existing = ctx.db.npc_belief().iter()
                .find(|b| b.npc_id == npc.id && b.subject == *subject && b.predicate == *predicate);
            if let Some(existing) = existing {
                ctx.db.npc_belief().id().update(NpcBelief {
                    object: object.clone(), confidence: 1.0, updated_at: now_us, ..existing
                });
            } else {
                ctx.db.npc_belief().insert(NpcBelief {
                    id: 0, npc_id: npc.id,
                    subject: subject.clone(), predicate: predicate.clone(), object: object.clone(),
                    confidence: 1.0, updated_at: now_us,
                });
            }
        }
        NpcBtAction::RequestLlmDecision(reason) => {
            if !has_pending_decision(ctx, npc.id) {
                log_npc_event(ctx, npc.id, "self_request", &format!(r#"{{"reason":"{}"}}"#, reason.replace('"', "\\\"")) );
                trigger_decision(ctx, npc, "significant", None);
            }
        }

        // ── v2: Entity-targeting actions ──
        NpcBtAction::TravelToEntity { entity_type, entity_id } => {
            let pos = match entity_type.as_str() {
                "npc" => ctx.db.npc().id().find(entity_id).map(|n| (n.position.x, n.position.z)),
                "poi" => ctx.db.point_of_interest().id().find(entity_id).map(|p| (p.x, p.z)),
                _ => None,
            };
            if let Some((x, z)) = pos {
                execute_bt_action(ctx, npc, &NpcBtAction::TravelTo { x, z }, None);
            } else {
                log::warn!("[NPC {}] TravelToEntity: {} {} not found", npc.id, entity_type, entity_id);
            }
        }
        NpcBtAction::AttackEntity { entity_type, entity_id } => {
            match entity_type.as_str() {
                "player" => {
                    // Find player by identity hex stored in entity_id — for now just attack nearest
                    if let Some(player) = target {
                        execute_bt_action(ctx, npc, &NpcBtAction::Attack, Some(player));
                    }
                }
                "npc" => {
                    if let Some(target_npc) = ctx.db.npc().id().find(entity_id) {
                        if npc.position.distance_to(&target_npc.position) <= ATTACK_RANGE {
                            let dmg = crate::skill::npc_damage(npc.level);
                            let new_health = target_npc.health - dmg;
                            if new_health <= 0 {
                                crate::combat::kill_npc(ctx, &target_npc, spacetimedb::Identity::__dummy());
                            } else {
                                ctx.db.npc().id().update(Npc { health: new_health, ..target_npc });
                            }
                        }
                    }
                }
                _ => {}
            }
        }
        NpcBtAction::SayToEntity { entity_type, entity_id, message } => {
            match entity_type.as_str() {
                "npc" => {
                    execute_bt_action(ctx, npc, &NpcBtAction::SayToNpc {
                        npc_id: *entity_id, message: message.clone(),
                    }, None);
                }
                _ => {
                    // For players and others, just broadcast as regular say
                    execute_bt_action(ctx, npc, &NpcBtAction::Say(message.clone()), None);
                }
            }
        }

        // ── v2: Exploration ──
        NpcBtAction::SearchFor(_category) => {
            // Wander randomly; actual discovery logic added in Step 8
            execute_bt_action(ctx, npc, &NpcBtAction::Wander, None);
        }

        // ── v2: Inline identity updates ──
        NpcBtAction::AddKnowledge { category, fact } => {
            let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
            let existing = ctx.db.npc_knowledge().iter()
                .find(|k| k.npc_id == npc.id && k.category == *category && k.fact == *fact);
            if existing.is_none() {
                let count = ctx.db.npc_knowledge().iter().filter(|k| k.npc_id == npc.id).count();
                if count < MAX_NPC_KNOWLEDGE {
                    ctx.db.npc_knowledge().insert(NpcKnowledge {
                        id: 0, npc_id: npc.id,
                        category: category.clone(), fact: fact.clone(),
                        learned_from: "experience".to_string(), confidence: 1.0,
                        created_at: now_us,
                    });
                    log::info!("[NPC {}] learned: [{}] {}", npc.id, category, fact);
                }
            }
        }
        NpcBtAction::AdjustRelationship { target: rel_target, delta } => {
            let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
            let (target_type, target_id) = if rel_target.starts_with("player:") {
                ("player".to_string(), rel_target.trim_start_matches("player:").to_string())
            } else if rel_target.starts_with("npc:") {
                ("npc".to_string(), rel_target.trim_start_matches("npc:").to_string())
            } else {
                ("unknown".to_string(), rel_target.clone())
            };
            let existing = ctx.db.npc_relationship().iter()
                .find(|r| r.npc_id == npc.id && r.target_type == target_type && r.target_id == target_id);
            if let Some(existing) = existing {
                let new_disp = (existing.disposition + delta).clamp(-100, 100);
                ctx.db.npc_relationship().id().update(NpcRelationship {
                    disposition: new_disp, updated_at: now_us, ..existing
                });
            } else {
                ctx.db.npc_relationship().insert(NpcRelationship {
                    id: 0, npc_id: npc.id, target_type, target_id,
                    disposition: (*delta).clamp(-100, 100),
                    context: String::new(), updated_at: now_us,
                });
            }
        }
        NpcBtAction::TriggerEmotionAction { emotion, delta } => {
            trigger_emotion(ctx, npc.id, emotion, *delta);
        }

        // ── v2: Conversation protocol ──
        NpcBtAction::SayTemplate(template_id) => {
            let text = get_template_text(template_id);
            if !text.is_empty() {
                execute_bt_action(ctx, npc, &NpcBtAction::Say(text), None);
            }
        }
        NpcBtAction::SayFromKnowledge(topic) => {
            let knowledge = ctx.db.npc_knowledge().iter()
                .find(|k| k.npc_id == npc.id && (k.category.contains(topic.as_str()) || k.fact.contains(topic.as_str())));
            if let Some(k) = knowledge {
                execute_bt_action(ctx, npc, &NpcBtAction::Say(k.fact.clone()), None);
            }
        }
        NpcBtAction::SayFromBelief(topic) => {
            let belief = ctx.db.npc_belief().iter()
                .find(|b| b.npc_id == npc.id && (b.subject.contains(topic.as_str()) || b.predicate.contains(topic.as_str())));
            if let Some(b) = belief {
                let text = format!("I believe {} {} {}.", b.subject, b.predicate, b.object);
                execute_bt_action(ctx, npc, &NpcBtAction::Say(text), None);
            }
        }

        // ── v2: Tree lifecycle ──
        NpcBtAction::RequestNewTree => {
            if !has_pending_decision(ctx, npc.id) {
                log_npc_event(ctx, npc.id, "self_request", r#"{"reason":"tree_exhaustion"}"#);
                trigger_decision(ctx, npc, "tree_generation", None);
            }
        }
        NpcBtAction::KeepDistance(min_distance) => {
            if let Some(player) = target {
                let dist = npc.position.distance_to(&player.position);
                if dist < *min_distance {
                    // Move away
                    execute_bt_action(ctx, npc, &NpcBtAction::Flee, target);
                }
            }
        }
        NpcBtAction::Follow { distance } => {
            if let Some(player) = target {
                let dist = npc.position.distance_to(&player.position);
                if dist > *distance {
                    execute_bt_action(ctx, npc, &NpcBtAction::Chase, target);
                }
                // else: already close enough, stand still
            }
        }

        // ── Conditions are not executed as actions ──
        NpcBtAction::EnemyInRange | NpcBtAction::EnemyDetected | NpcBtAction::HealthBelow(_)
        | NpcBtAction::NoTarget | NpcBtAction::IsNightTime | NpcBtAction::IsDayTime
        | NpcBtAction::GoldAbove(_) | NpcBtAction::GoldBelow(_) | NpcBtAction::HasItem(_)
        | NpcBtAction::NpcNearby | NpcBtAction::NpcNearbyWithRole(_) | NpcBtAction::PlayerNearby
        | NpcBtAction::AtPoi(_) | NpcBtAction::GoalActive(_) | NpcBtAction::ManaAbove(_)
        | NpcBtAction::StaminaAbove(_)
        | NpcBtAction::EmotionAbove(_, _) | NpcBtAction::EmotionBelow(_, _)
        | NpcBtAction::EmotionDominant(_) | NpcBtAction::HasKnowledge(_)
        | NpcBtAction::StrengthAdvantage(_) | NpcBtAction::IsBeingAttacked
        | NpcBtAction::BeingAddressedInConversation => {}
    }
}

// ── Helper: upsert NpcBehavior (v2 unified tree) ──

pub fn upsert_npc_tree(ctx: &ReducerContext, npc_id: u64, tree_json: &str) {
    if ctx.db.npc_behavior().npc_id().find(&npc_id).is_some() {
        ctx.db.npc_behavior().npc_id().update(NpcBehavior {
            npc_id,
            current_tree: tree_json.to_string(),
        });
    } else {
        ctx.db.npc_behavior().insert(NpcBehavior {
            npc_id,
            current_tree: tree_json.to_string(),
        });
    }
}

// ── Helper: trigger a pending decision ──

pub fn trigger_decision(ctx: &ReducerContext, npc: &Npc, decision_type: &str, target: Option<&Player>) {
    if ctx.db.npc_pending_decision().npc_id().find(&npc.id).is_some() {
        return; // Already has a pending decision
    }

    let nearby_players = if let Some(player) = target {
        let dist = npc.position.distance_to(&player.position);
        format!(
            r#"[{{"identity":"{}","position":{{"x":{},"y":{},"z":{}}},"distance":{}}}]"#,
            player.identity.to_hex().to_string(),
            player.position.x, player.position.y, player.position.z, dist,
        )
    } else {
        "[]".to_string()
    };

    let plan_context = "";

    // Collect recent events (short-term memory)
    let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
    let mut recent_events = Vec::new();
    for evt in ctx.db.npc_event_log().iter() {
        if evt.npc_id == npc.id {
            // scheduled_at is the expiry time; event was created NPC_EVENT_EXPIRE_MS before that
            let expiry_us = match &evt.scheduled_at {
                ScheduleAt::Time(t) => t.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64,
                _ => 0,
            };
            let remaining_ms = expiry_us.saturating_sub(now_us) / 1000;
            let age_seconds = (NPC_EVENT_EXPIRE_MS.saturating_sub(remaining_ms)) / 1000;
            recent_events.push(format!(
                r#"{{"event":"{}","detail":{},"age_seconds":{}}}"#,
                evt.event, evt.detail, age_seconds,
            ));
        }
    }
    let recent_events_json = format!("[{}]", recent_events.join(","));

    // Collect long-term memories
    let mut memories = Vec::new();
    for mem in ctx.db.npc_memory().iter() {
        if mem.npc_id == npc.id {
            memories.push(format!("\"{}\"", mem.text.replace('\"', "\\\"")));
        }
    }
    let memories_json = format!("[{}]", memories.join(","));

    let context = format!(
        r#"{{"npc_id":{},"npc_name":"{}","npc_role":"{}","npc_level":{},"npc_position":{{"x":{},"y":{},"z":{}}},"npc_health":{},"npc_max_health":{},"nearby_players":{},"attack_range":{},"recent_events":{},"memories":{}{}}}"#,
        npc.id, npc.name.replace('\"', "\\\""), npc.role,
        npc.level, npc.position.x, npc.position.y, npc.position.z,
        npc.health, npc.max_health, nearby_players, ATTACK_RANGE,
        recent_events_json, memories_json, plan_context,
    );

    log::info!("[NPC {}] triggering {} decision", npc.id, decision_type);
    ctx.db.npc_pending_decision().insert(NpcPendingDecision {
        npc_id: npc.id,
        decision_type: decision_type.to_string(),
        context,
    });
}

pub fn has_pending_decision(ctx: &ReducerContext, npc_id: u64) -> bool {
    ctx.db.npc_pending_decision().npc_id().find(&npc_id).is_some()
}

/// Social cooldown: 30 seconds between social decision triggers.
pub const SOCIAL_COOLDOWN_MS: u64 = 30_000;

/// Check if an NPC has a recent event of the given type within `max_age_ms`.
pub fn has_recent_event(ctx: &ReducerContext, npc_id: u64, event_type: &str, max_age_ms: u64) -> bool {
    let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
    for evt in ctx.db.npc_event_log().iter() {
        if evt.npc_id == npc_id && evt.event == event_type {
            let expiry_us = match &evt.scheduled_at {
                ScheduleAt::Time(t) => t.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64,
                _ => 0,
            };
            let created_us = expiry_us.saturating_sub(NPC_EVENT_EXPIRE_MS * 1000);
            let age_ms = now_us.saturating_sub(created_us) / 1000;
            if age_ms <= max_age_ms {
                return true;
            }
        }
    }
    false
}

/// Check if there's an unhandled player chat: heard_chat exists and is newer than responded_to_chat.
pub fn has_unhandled_chat(ctx: &ReducerContext, npc_id: u64) -> bool {
    let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
    let mut latest_heard: u64 = 0;
    let mut latest_responded: u64 = 0;
    for evt in ctx.db.npc_event_log().iter() {
        if evt.npc_id != npc_id { continue; }
        let expiry_us = match &evt.scheduled_at {
            ScheduleAt::Time(t) => t.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64,
            _ => 0,
        };
        let created_us = expiry_us.saturating_sub(NPC_EVENT_EXPIRE_MS * 1000);
        let age_ms = now_us.saturating_sub(created_us) / 1000;
        if age_ms > SOCIAL_COOLDOWN_MS { continue; }
        if evt.event == "heard_chat" && created_us > latest_heard {
            latest_heard = created_us;
        }
        if evt.event == "responded_to_chat" && created_us > latest_responded {
            latest_responded = created_us;
        }
    }
    latest_heard > 0 && latest_heard > latest_responded
}

// ── Helper: log an NPC event (short-term memory, auto-expires) ──

pub const NPC_EVENT_EXPIRE_MS: u64 = 300_000; // 5 minutes

pub fn log_npc_event(ctx: &ReducerContext, npc_id: u64, event: &str, detail: &str) {
    ctx.db.npc_event_log().insert(NpcEventLog {
        scheduled_id: 0,
        scheduled_at: ScheduleAt::Time(ctx.timestamp + Duration::from_millis(NPC_EVENT_EXPIRE_MS)),
        npc_id,
        event: event.to_string(),
        detail: detail.to_string(),
    });
}

// ── Sleep/wake helpers ──

// ── Goal completion checking ──

pub fn check_goal_conditions(ctx: &ReducerContext, npc: &Npc) {
    let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
    for goal in ctx.db.npc_goal().iter().collect::<Vec<_>>() {
        if goal.npc_id != npc.id || goal.status != GoalStatus::Active { continue; }
        if goal.success_condition.is_empty() { continue; }

        let v: serde_json::Value = match serde_json::from_str(&goal.success_condition) {
            Ok(v) => v,
            Err(_) => continue,
        };

        let completed = match v.get("type").and_then(|t| t.as_str()) {
            Some("gold_above") => {
                let amount = v.get("amount").and_then(|a| a.as_i64()).unwrap_or(0) as i32;
                npc.gold >= amount
            }
            Some("level_above") => {
                let lvl = v.get("level").and_then(|l| l.as_i64()).unwrap_or(0) as i32;
                npc.level >= lvl
            }
            Some("reach") => {
                let tx = v.get("x").and_then(|x| x.as_f64()).unwrap_or(0.0) as f32;
                let tz = v.get("z").and_then(|z| z.as_f64()).unwrap_or(0.0) as f32;
                let dx = npc.position.x - tx;
                let dz = npc.position.z - tz;
                (dx * dx + dz * dz).sqrt() <= 5.0
            }
            _ => false,
        };

        if completed {
            ctx.db.npc_goal().id().update(NpcGoal {
                status: GoalStatus::Completed,
                completed_at: now_us,
                ..goal
            });
            log_npc_event(ctx, npc.id, "goal_completed", "{}");
            // Emotion: achieving a goal brings joy
            trigger_emotion(ctx, npc.id, "joy", 0.4);
        }
    }
}

// ── Find nearby NPCs ──

pub fn find_nearby_npcs(ctx: &ReducerContext, npc: &Npc) -> Vec<Npc> {
    ctx.db.npc().iter()
        .filter(|n| n.id != npc.id && npc.position.distance_to(&n.position) <= NPC_DETECTION_RANGE)
        .collect()
}

// ── Find nearby POIs ──

pub fn find_nearby_pois(ctx: &ReducerContext, npc: &Npc) -> Vec<(PointOfInterest, f32)> {
    ctx.db.point_of_interest().iter()
        .map(|poi| {
            let dx = npc.position.x - poi.x;
            let dz = npc.position.z - poi.z;
            let d = (dx * dx + dz * dz).sqrt();
            (poi, d)
        })
        .filter(|(_, d)| *d <= NPC_DETECTION_RANGE)
        .collect()
}

// ── World time helpers ──

#[allow(dead_code)]
pub fn get_world_time(ctx: &ReducerContext) -> (bool, u64) {
    if let Some(ws) = ctx.db.world_state().id().find(&0) {
        let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
        let elapsed_ms = (now_us.saturating_sub(ws.cycle_start_us)) / 1000;
        let cycle_pos = elapsed_ms % WORLD_CYCLE_MS;
        let is_night = cycle_pos >= DAY_DURATION_MS;
        (is_night, cycle_pos)
    } else {
        (false, 0)
    }
}

/// Check and handle day/night transitions. Returns the current is_night state.
pub fn update_day_night_cycle(ctx: &ReducerContext) -> bool {
    let Some(ws) = ctx.db.world_state().id().find(&0) else { return false };
    let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
    let elapsed_ms = (now_us.saturating_sub(ws.cycle_start_us)) / 1000;
    let cycle_pos = elapsed_ms % WORLD_CYCLE_MS;
    let is_night = cycle_pos >= DAY_DURATION_MS;

    // Detect transition
    if is_night != ws.is_night {
        log::info!("Day/night transition: {} → {}", if ws.is_night { "night" } else { "day" }, if is_night { "night" } else { "day" });

        // Reset cycle start on full cycle rollover
        let new_cycle_start = if elapsed_ms >= WORLD_CYCLE_MS {
            now_us - (cycle_pos * 1000)
        } else {
            ws.cycle_start_us
        };

        ctx.db.world_state().id().update(WorldState {
            id: 0, cycle_start_us: new_cycle_start, is_night,
        });

        // Trigger tree regeneration for all NPCs at dawn
        // (night behavior is handled by IsNightTime conditions in the unified tree)
        if !is_night {
            for npc in ctx.db.npc().iter().collect::<Vec<_>>() {
                if !has_pending_decision(ctx, npc.id) {
                    trigger_decision_enriched(ctx, &npc, "tree_generation", None, is_night);
                }
            }
        }
    }

    is_night
}

// ── Default unified trees ──

/// Build a complete unified behavior tree for an NPC role.
/// Contains all four priority layers: reactive, awareness, daily life, fallback.
/// Used as the default tree when no LLM-generated tree exists.
pub fn default_unified_tree(role: &str) -> Behavior<NpcBtAction> {
    use Behavior::{Action, Select, Sequence};

    // Reactive layer (shared across most roles)
    let reactive_combat = Sequence(vec![
        Action(NpcBtAction::IsBeingAttacked),
        Select(vec![
            Sequence(vec![
                Action(NpcBtAction::HealthBelow(0.25)),
                Action(NpcBtAction::Say("I must retreat!".into())),
                Action(NpcBtAction::Flee),
            ]),
            Action(NpcBtAction::Attack),
        ]),
    ]);
    let reactive_conversation = Sequence(vec![
        Action(NpcBtAction::BeingAddressedInConversation),
        Action(NpcBtAction::SayTemplate("generic_acknowledgment".into())),
    ]);

    match role {
        "hostile" | "hostile_defensive" => {
            // Hostile: attack on sight, flee when low
            Select(vec![
                reactive_combat,
                // Awareness: attack if enemy detected and strong enough
                Sequence(vec![
                    Action(NpcBtAction::EnemyDetected),
                    Action(NpcBtAction::StrengthAdvantage(-0.3)),
                    Action(NpcBtAction::EmotionBelow("fear".into(), 0.7)),
                    Action(NpcBtAction::Attack),
                ]),
                // Flee if outmatched
                Sequence(vec![
                    Action(NpcBtAction::EnemyDetected),
                    Action(NpcBtAction::Flee),
                ]),
                // Night: go home and rest
                Sequence(vec![
                    Action(NpcBtAction::IsNightTime),
                    Action(NpcBtAction::GoHome),
                    Action(NpcBtAction::Rest),
                ]),
                Action(NpcBtAction::Wander),
            ])
        }
        "guard" => {
            Select(vec![
                reactive_combat,
                reactive_conversation.clone(),
                // Awareness: chase enemies if brave enough
                Sequence(vec![
                    Action(NpcBtAction::EnemyDetected),
                    Action(NpcBtAction::EmotionBelow("fear".into(), 0.6)),
                    Action(NpcBtAction::StrengthAdvantage(-0.2)),
                    Action(NpcBtAction::Chase),
                ]),
                // Keep distance if outmatched
                Sequence(vec![
                    Action(NpcBtAction::EnemyDetected),
                    Action(NpcBtAction::KeepDistance(12.0)),
                ]),
                // Night: patrol station
                Sequence(vec![
                    Action(NpcBtAction::IsNightTime),
                    Action(NpcBtAction::TravelToPoi("North Gate".into())),
                    Action(NpcBtAction::Rest),
                ]),
                // Day: patrol
                Sequence(vec![
                    Action(NpcBtAction::IsDayTime),
                    Action(NpcBtAction::TravelToPoi("North Gate".into())),
                    Action(NpcBtAction::Wait(5.0)),
                ]),
                Action(NpcBtAction::Wander),
            ])
        }
        "trader" => {
            Select(vec![
                // Traders flee from combat instead of fighting
                Sequence(vec![
                    Action(NpcBtAction::IsBeingAttacked),
                    Action(NpcBtAction::Flee),
                ]),
                reactive_conversation.clone(),
                // Flee if enemy spotted and scared
                Sequence(vec![
                    Action(NpcBtAction::EnemyDetected),
                    Action(NpcBtAction::EmotionAbove("fear".into(), 0.3)),
                    Action(NpcBtAction::Flee),
                ]),
                // Night: go home
                Sequence(vec![
                    Action(NpcBtAction::IsNightTime),
                    Action(NpcBtAction::GoHome),
                    Action(NpcBtAction::Rest),
                ]),
                // Day: go to market
                Sequence(vec![
                    Action(NpcBtAction::IsDayTime),
                    Action(NpcBtAction::TravelToPoi("Market Square".into())),
                    Action(NpcBtAction::Wait(10.0)),
                ]),
                Action(NpcBtAction::Wander),
            ])
        }
        "healer" => {
            Select(vec![
                Sequence(vec![
                    Action(NpcBtAction::IsBeingAttacked),
                    Action(NpcBtAction::Flee),
                ]),
                reactive_conversation.clone(),
                Sequence(vec![
                    Action(NpcBtAction::IsNightTime),
                    Action(NpcBtAction::GoHome),
                    Action(NpcBtAction::Rest),
                ]),
                Action(NpcBtAction::Rest),
            ])
        }
        "historian" => {
            Select(vec![
                Sequence(vec![
                    Action(NpcBtAction::IsBeingAttacked),
                    Action(NpcBtAction::Flee),
                ]),
                reactive_conversation.clone(),
                Sequence(vec![
                    Action(NpcBtAction::IsNightTime),
                    Action(NpcBtAction::GoHome),
                    Action(NpcBtAction::Rest),
                ]),
                Action(NpcBtAction::Wait(10.0)),
            ])
        }
        "adventurer" => {
            Select(vec![
                reactive_combat.clone(),
                reactive_conversation,
                // Adventurers attack if they can win
                Sequence(vec![
                    Action(NpcBtAction::EnemyDetected),
                    Action(NpcBtAction::StrengthAdvantage(-0.1)),
                    Action(NpcBtAction::EmotionBelow("fear".into(), 0.5)),
                    Action(NpcBtAction::Attack),
                ]),
                Sequence(vec![
                    Action(NpcBtAction::EnemyDetected),
                    Action(NpcBtAction::KeepDistance(10.0)),
                ]),
                Sequence(vec![
                    Action(NpcBtAction::IsNightTime),
                    Action(NpcBtAction::GoHome),
                    Action(NpcBtAction::Rest),
                ]),
                Action(NpcBtAction::Wander),
            ])
        }
        "traveller" => {
            Select(vec![
                Sequence(vec![
                    Action(NpcBtAction::IsBeingAttacked),
                    Action(NpcBtAction::Flee),
                ]),
                Sequence(vec![
                    Action(NpcBtAction::EnemyDetected),
                    Action(NpcBtAction::Flee),
                ]),
                Sequence(vec![
                    Action(NpcBtAction::IsNightTime),
                    Action(NpcBtAction::GoHome),
                    Action(NpcBtAction::Rest),
                ]),
                Action(NpcBtAction::Wander),
            ])
        }
        // Unknown: simple mob behavior
        _ => {
            Select(vec![
                Sequence(vec![
                    Action(NpcBtAction::IsBeingAttacked),
                    Select(vec![
                        Sequence(vec![Action(NpcBtAction::HealthBelow(0.25)), Action(NpcBtAction::Flee)]),
                        Action(NpcBtAction::Attack),
                    ]),
                ]),
                Sequence(vec![
                    Action(NpcBtAction::IsNightTime),
                    Action(NpcBtAction::Rest),
                ]),
                Action(NpcBtAction::Wander),
            ])
        }
    }
}

// ── Enriched trigger_decision with BDI context ──

pub fn trigger_decision_enriched(
    ctx: &ReducerContext, npc: &Npc, decision_type: &str,
    target: Option<&Player>, is_night: bool,
) {
    if ctx.db.npc_pending_decision().npc_id().find(&npc.id).is_some() {
        return; // Already has a pending decision
    }

    // Nearby players
    let nearby_players: Vec<String> = if let Some(player) = target {
        let dist = npc.position.distance_to(&player.position);
        vec![format!(
            r#"{{"identity":"{}","position":{{"x":{},"y":{},"z":{}}},"distance":{:.1}}}"#,
            player.identity.to_hex().to_string(),
            player.position.x, player.position.y, player.position.z, dist,
        )]
    } else {
        Vec::new()
    };

    // Nearby NPCs
    let nearby_npcs: Vec<String> = find_nearby_npcs(ctx, npc).iter().map(|n| {
        let d = npc.position.distance_to(&n.position);
        format!(r#"{{"id":{},"name":"{}","role":"{}","distance":{:.1}}}"#,
            n.id, n.name.replace('"', "\\\""), n.role, d)
    }).collect();

    // Nearby POIs
    let nearby_pois: Vec<String> = find_nearby_pois(ctx, npc).iter().map(|(poi, d)| {
        format!(r#"{{"name":"{}","type":"{}","distance":{:.1}}}"#,
            poi.name.replace('"', "\\\""), poi.poi_type, d)
    }).collect();

    // Goals
    let goals: Vec<String> = ctx.db.npc_goal().iter()
        .filter(|g| g.npc_id == npc.id && g.status == GoalStatus::Active)
        .map(|g| {
            format!(r#"{{"description":"{}","priority":"{:?}","status":"{:?}"}}"#,
                g.description.replace('"', "\\\""), g.priority, g.status)
        }).collect();

    // Beliefs
    let beliefs: Vec<String> = ctx.db.npc_belief().iter()
        .filter(|b| b.npc_id == npc.id)
        .map(|b| {
            format!(r#"{{"subject":"{}","predicate":"{}","object":"{}","confidence":{:.1}}}"#,
                b.subject, b.predicate, b.object, b.confidence)
        }).collect();

    // Relationships
    let relationships: Vec<String> = ctx.db.npc_relationship().iter()
        .filter(|r| r.npc_id == npc.id)
        .map(|r| {
            format!(r#"{{"target_type":"{}","target_id":"{}","disposition":{},"context":"{}"}}"#,
                r.target_type, r.target_id, r.disposition, r.context.replace('"', "\\\""))
        }).collect();

    // Inventory
    let inventory: Vec<String> = ctx.db.npc_inventory_item().iter()
        .filter(|inv| inv.npc_id == npc.id)
        .filter_map(|inv| {
            ctx.db.item_def().id().find(&inv.item_def_id).map(|item| {
                format!(r#"{{"item":"{}","quantity":{},"slot":{}}}"#, item.name, inv.quantity, inv.slot)
            })
        }).collect();

    // Equipment
    let equipment: Vec<String> = ctx.db.npc_equipped_item().iter()
        .filter(|eq| eq.npc_id == npc.id)
        .filter_map(|eq| {
            ctx.db.item_def().id().find(&eq.item_def_id).map(|item| {
                format!(r#"{{"slot":"{:?}","item":"{}"}}"#, eq.equip_slot, item.name)
            })
        }).collect();

    // Recent events & memories (same as original trigger_decision)
    let now_us = ctx.timestamp.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64;
    let mut recent_events = Vec::new();
    for evt in ctx.db.npc_event_log().iter() {
        if evt.npc_id == npc.id {
            let expiry_us = match &evt.scheduled_at {
                ScheduleAt::Time(t) => t.to_duration_since_unix_epoch().unwrap_or_default().as_micros() as u64,
                _ => 0,
            };
            let remaining_ms = expiry_us.saturating_sub(now_us) / 1000;
            let age_seconds = (NPC_EVENT_EXPIRE_MS.saturating_sub(remaining_ms)) / 1000;
            recent_events.push(format!(
                r#"{{"event":"{}","detail":{},"age_seconds":{}}}"#,
                evt.event, evt.detail, age_seconds,
            ));
        }
    }
    let mut memories = Vec::new();
    for mem in ctx.db.npc_memory().iter() {
        if mem.npc_id == npc.id {
            memories.push(format!("\"{}\"", mem.text.replace('"', "\\\"")));
        }
    }

    // Extract the most recent player chat message for prominent placement
    let mut player_said = String::new();
    for evt in ctx.db.npc_event_log().iter() {
        if evt.npc_id == npc.id && evt.event == "heard_chat" {
            if let Ok(v) = serde_json::from_str::<serde_json::Value>(&evt.detail) {
                if let Some(text) = v.get("text").and_then(|t| t.as_str()) {
                    player_said = text.to_string();
                }
            }
        }
    }
    let player_said_field = if player_said.is_empty() {
        String::new()
    } else {
        format!(r#""player_said":"{}","#, player_said.replace('"', "\\\""))
    };

    let context = format!(
        concat!(
            r#"{{"npc_id":{},"npc_name":"{}","npc_role":"{}","persona":"{}","#,
            r#"{}"#,
            r#""npc_level":{},"npc_health":{},"npc_max_health":{},"#,
            r#""gold":{},"mana":{},"max_mana":{},"stamina":{},"max_stamina":{},"#,
            r#""npc_position":{{"x":{},"y":{},"z":{}}},"#,
            r#""world_time":"{}","#,
            r#""goals":[{}],"beliefs":[{}],"relationships":[{}],"#,
            r#""inventory":[{}],"equipment":[{}],"#,
            r#""nearby_players":[{}],"nearby_npcs":[{}],"nearby_pois":[{}],"#,
            r#""attack_range":{},"recent_events":[{}],"memories":[{}]}}"#
        ),
        npc.id, npc.name.replace('"', "\\\""), npc.role, npc.persona.replace('"', "\\\""),
        player_said_field,
        npc.level, npc.health, npc.max_health,
        npc.gold, npc.mana, npc.max_mana, npc.stamina, npc.max_stamina,
        npc.position.x, npc.position.y, npc.position.z,
        if is_night { "night" } else { "day" },
        goals.join(","), beliefs.join(","), relationships.join(","),
        inventory.join(","), equipment.join(","),
        nearby_players.join(","), nearby_npcs.join(","), nearby_pois.join(","),
        ATTACK_RANGE, recent_events.join(","), memories.join(","),
    );

    log::info!("[NPC {}] triggering {} decision (enriched)", npc.id, decision_type);
    ctx.db.npc_pending_decision().insert(NpcPendingDecision {
        npc_id: npc.id,
        decision_type: decision_type.to_string(),
        context,
    });
}
